let litCells = [];
let playerClicks = [];
let level = 2;

function startRound(cells, clicks) {
    playerClicks = [];
    litCells = cells;
    console.log('Round starts. litCells:', litCells);

    // simulate player clicking
    clicks.forEach(function(c) { playerClicks.push(c); });
    console.log('Player clicked:', playerClicks);

    checkResult();
}

function checkResult() {
    let a = litCells.slice().sort().toString();
    let b = playerClicks.slice().sort().toString();
    if (a === b) {
        level = level + 1;
        console.log('Correct! Level is now:', level);
    } else {
        level = 2;
        console.log('Wrong. Back to level 2.');
    }
}

// Round 1: correct
startRound([3, 7], [7, 3]);

// Round 2: correct
startRound([1, 5, 8], [5, 1, 8]);

